// ============================ FROST 霜寒冰原 — ground decals + standing decor ============================
// Follows the bd_frost_* art direction already in src/art/biome_decor.js: cool blue-white
// ice (P.ice/P.iceD/P.hiSky/P.rimCool) over grey stone/wood, rimLight(P.rimCool) + outline(P.ink)
// on every standing prop. Ground decals stay LOW-CONTRAST (no outline, no big glow, no
// bright green/teal) so they read as ground texture, never confusable with pickups.

// Reference "snow floor" anchor tone (the biome's floor isn't defined in this file, so this
// approximates it from the existing bd_frost_* accent palette: a pale ice/white blend).
// Every decal below sits within ~10-18% lightness of this anchor via lighten/darken.
const FR_FLOOR = mix(P.white, P.ice, 0.45);
const FR_LO1 = darken(FR_FLOOR, 0.1);
const FR_LO2 = darken(FR_FLOOR, 0.16);
const FR_HI1 = lighten(FR_FLOOR, 0.1);
const FR_HI2 = lighten(FR_FLOOR, 0.16);

// Frost-stiffened cloth tone for the banner (no dedicated palette entry — blended from
// existing keys the same way bd_swamp_* blends P.bark/P.murk).
const FR_CLOTH = mix(P.gray3, P.ice, 0.25);
const FR_CLOTHD = darken(FR_CLOTH, 0.22);

// ---------------------------------------------------------------------------------------
// (a) ground decals — anchored at each sprite's own centre, no outline, no random()
// ---------------------------------------------------------------------------------------

defineSprite('decal_frost_crack_a', 10, 5, (p) => {          // hairline ice crack
  p.line(1, 4, 4, 2, FR_LO2);
  p.line(4, 2, 7, 3, FR_LO1);
  p.line(7, 3, 9, 1, FR_LO2);
  p.px(4, 2, FR_HI1); p.px(7, 3, FR_HI1);
}, { anchor: [5, 3] });

defineSprite('decal_frost_crack_b', 13, 6, (p) => {          // branching ice crack
  p.line(1, 5, 6, 2, FR_LO2);
  p.line(6, 2, 11, 4, FR_LO1);
  p.line(6, 2, 3, 4, FR_LO1);
  p.line(11, 4, 9, 5, FR_LO2);
  p.px(6, 2, FR_HI1); p.px(3, 4, FR_HI2); p.px(9, 5, FR_HI1);
}, { anchor: [7, 3] });

defineSprite('decal_frost_drift_a', 14, 6, (p) => {          // wind-blown snow streak
  p.ellipse(7, 3, 6, 1.6, FR_HI1);
  p.ellipse(4, 3, 3, 1, FR_HI2);
  p.ellipse(10, 3, 3, 1, FR_LO1);
  p.dither(1, 2, 12, 2, FR_FLOOR, FR_HI1);
}, { anchor: [7, 3] });

defineSprite('decal_frost_drift_b', 11, 5, (p) => {          // short snow drift streak
  p.ellipse(5, 3, 4, 1.4, FR_HI1);
  p.ellipse(8, 3, 2, 1, FR_LO1);
  p.px(3, 2, FR_HI2); p.px(7, 3, FR_LO2);
}, { anchor: [6, 3] });

defineSprite('decal_frost_patch', 10, 7, (p) => {            // pale frozen ground patch, faint sheen
  p.ellipse(5, 4, 4, 2.6, FR_HI1);
  p.ellipse(5, 3, 2.6, 1.6, FR_HI2);
  p.speckle(1, 2, 7, 4, FR_LO1, 3, 12);
  p.px(5, 3, withAlpha(P.rimCool, 0.22));                    // subtle glow #1 — faint frosty sheen
}, { anchor: [5, 4] });

defineSprite('decal_frost_rime', 8, 5, (p) => {              // hoarfrost stipple patch
  p.speckle(0, 0, 8, 5, FR_HI1, 6, 27);
  p.speckle(0, 0, 8, 5, FR_LO1, 4, 44);
}, { anchor: [4, 3] });

defineSprite('decal_frost_bootprint', 10, 6, (p) => {        // faint boot prints in snow
  p.ellipse(3, 3, 1.6, 1.2, FR_LO1);
  p.ellipse(7, 4, 1.6, 1.2, FR_LO2);
  p.px(3, 3, FR_LO2); p.px(7, 4, FR_LO1);
}, { anchor: [5, 3] });

defineSprite('decal_frost_glimmer', 9, 5, (p) => {           // faint frost glint on the ground
  p.ellipse(5, 3, 3.6, 1.6, FR_HI1);
  p.px(5, 2, withAlpha(P.hiSky, 0.28));                      // subtle glow #2
  p.px(7, 3, FR_HI2);
}, { anchor: [5, 3] });

// ---------------------------------------------------------------------------------------
// (b) standing decor — anchored at ground contact, softShadow + rimLight(P.rimCool) +
// outline(P.ink), same finishing order as the existing bd_frost_* props.
// ---------------------------------------------------------------------------------------

defineSprite('bdx_frost_shrub', 14, 16, (p) => {             // frost-glazed dead shrub
  p.softShadow(7, 15, 6, 1.6, 0.38);
  p.line(7, 15, 4, 8, P.gray1); p.line(7, 15, 10, 8, P.gray1); p.line(7, 15, 7, 6, P.gray2);
  p.line(4, 8, 2, 4, P.gray1); p.line(10, 8, 12, 4, P.gray1); p.line(7, 6, 5, 2, P.gray2); p.line(7, 6, 9, 3, P.gray2);
  p.vline(12, 15, 7, lighten(P.gray2, 0.12));
  // ice glaze on the branch tips
  p.px(2, 4, P.ice); p.px(12, 4, P.ice); p.px(5, 2, P.white); p.px(9, 3, P.white); p.px(7, 6, P.ice);
  // short icicle drips
  p.vline(8, 9, 4, P.ice); p.vline(8, 9, 10, P.ice);
  p.rimLight(P.rimCool, 0.4);
  p.outline(P.ink);
}, { anchor: [7, 15] });

defineSprite('bdx_frost_snowpile', 16, 10, (p) => {          // packed snow mound, frozen crust
  p.softShadow(8, 9, 7, 1.4, 0.32);
  p.ellipse(8, 7, 7, 3, P.white); p.ellipse(6, 5, 4, 2, lighten(P.ice, 0.15)); p.ellipse(11, 6, 3, 1.8, P.white);
  p.gradV(2, 5, 12, 3, P.white, P.ice);
  // frozen crust cracks + a half-buried ice chunk
  p.line(5, 6, 8, 8, P.iceD); p.line(9, 5, 11, 7, P.iceD);
  p.rect(10, 5, 2, 2, P.ice); p.px(10, 5, P.white);
  p.px(4, 5, P.hiSky); p.px(9, 4, P.hiSky);
  p.rimLight(P.rimCool, 0.42);
  p.outline(P.iceD);
}, { anchor: [8, 9] });

defineSprite('bdx_frost_banner', 14, 24, (p) => {            // broken pole, frozen tattered banner
  p.softShadow(7, 23, 6, 1.6, 0.4);
  p.rect(6, 20, 2, 4, darken(P.woodD, 0.1));
  p.rect(6, 4, 2, 17, P.woodD); p.vline(4, 20, 6, lighten(P.woodD, 0.12));
  p.px(6, 4, P.wood);
  // tattered cloth, stiff-frozen, hanging with jagged torn edges
  p.rect(7, 5, 6, 10, FR_CLOTH);
  p.rect(7, 5, 2, 10, lighten(FR_CLOTH, 0.12));
  p.line(13, 6, 10, 9, FR_CLOTHD); p.line(13, 10, 9, 13, FR_CLOTHD); p.line(13, 14, 11, 15, FR_CLOTHD);
  p.px(9, 15, FR_CLOTHD); p.px(11, 15, FR_CLOTHD);
  // ice rime along the frozen fold lines + drips off the bottom edge
  p.hline(7, 12, 8, P.ice); p.hline(7, 12, 12, lighten(P.ice, 0.1));
  p.vline(15, 16, 8, P.ice); p.vline(15, 16, 11, P.ice);
  p.px(8, 5, P.white); p.px(12, 6, P.hiSky);
  p.rimLight(P.rimCool, 0.4);
  p.outline(P.ink);
}, { anchor: [7, 23] });

defineAnim('bdx_frost_iciclecluster', 16, 20, 2, (p, f) => { // standing icicle cluster, faint pulse
  p.softShadow(8, 18, 7, 2, 0.42);
  p.ellipse(8, 18, 7, 2.4, '#1a2436');
  p.line(8, 18, 5, 6, P.iceD); p.line(8, 18, 8, 2, P.ice); p.line(8, 18, 11, 7, P.iceD); p.line(8, 18, 7, 9, P.ice);
  p.line(6, 18, 4, 11, P.iceD); p.line(10, 18, 12, 10, P.ice);
  p.line(7, 18, 7, 8, lighten(P.ice, 0.2));
  p.glow(8, 10, 3 + f, P.ice, 0.28, 3);
  p.px(8, 2, P.white); p.px(5, 6, P.white); p.px(11, 7, P.hiSky);
  if (f === 0) p.star4(8, 3, 2, P.rimCool, P.white);
  p.rimLight(P.rimCool, 0.45);
  p.outline(P.ink);
}, { anchor: [8, 18], fps: 3 });

// ---------------------------------------------------------------------------------------
// registration
// ---------------------------------------------------------------------------------------
registerDecals('frost', [
  'decal_frost_crack_a', 'decal_frost_crack_b',
  'decal_frost_drift_a', 'decal_frost_drift_b',
  'decal_frost_patch', 'decal_frost_rime',
  'decal_frost_bootprint', 'decal_frost_glimmer',
]);
(DECOR_SETS['frost'] = DECOR_SETS['frost'] || []).push(
  'bdx_frost_shrub', 'bdx_frost_snowpile', 'bdx_frost_banner', 'bdx_frost_iciclecluster'
);
(DECOR_CLUSTERS['frost'] = DECOR_CLUSTERS['frost'] || []).push(
  'bdx_frost_iciclecluster'
);

